mapper.update:
update p_document
project_id = #{projectId}, name = #{name}, description = #{description}, remark = #{remark}, created_by = #{createdBy}, created_time = #{createdTime}, updated_time = #{updatedTime},
where id = #{id}

mapper.select:
select count(1) from p_document pd
inner join p_document_version pdv on pd.id = pdv.document_id
where pd.name = #{name} 
and pdv.version_number = #{version}

    and pd.id != #{id}
